): Promise<PrecedentAnalysisResult> => {
  const response = await ai.models.generateContent({
    model: MODEL_PRO,
    contents: `Analyze this judgment for key arguments, influencing statutes, and logical consistency. Document: ${documentText}`,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          keyArguments: {
            type: Type.OBJECT,
            properties: {
              plaintiff: { type: Type.STRING },
              defendant: { type: Type.STRING }
            }
          },
          influencingStatutes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                statute: { type: Type.STRING },
                quote: { type: Type.STRING },
                relevance: { type: Type.STRING }
              }
            }
          },
          consistencyCheck: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                issue: { type: Type.STRING },
                explanation: { type: Type.STRING }
              }
            }
          },
          biasDetection: {
            type: Type.OBJECT,
            properties: {
              warning: { type: Type.STRING }
            }
          }
        }
      }
    }
  });
  return JSON.parse(response.text);
};

