import { ChartBarIcon } from './icons/ChartBarIcon';
import { UsersIcon } from './icons/UsersIcon';
import { GavelIcon } from './icons/GavelIcon';
import { FileTextIcon } from './icons/FileTextIcon';
import { useTranslations } from '../hooks/useTranslations';
import { MailIcon } from './icons/MailIcon';
import { FlaskConicalIcon } from './icons/FlaskConicalIcon';
import { FileClockIcon } from './icons/FileClockIcon';
import { FeatherIcon } from './icons/FeatherIcon';
import { CalendarIcon } from './icons/CalendarIcon';
import { FEATURE_FLAGS } from '../featureFlags';


interface SidebarProps {
  userRole: UserRole;
  activeView: ViewType;
  setActiveView: (view: ViewType) => void;
}

interface NavItemProps {
  view: ViewType;
  label: string;
  icon: React.ReactNode;
  isActive: boolean;
  onClick: (view: ViewType) => void;
}

const NavItem: React.FC<NavItemProps> = ({ view, label, icon, isActive, onClick }) => (
  <button
    onClick={() => onClick(view)}
    className={`group w-full flex items-center px-4 py-3 text-sm font-medium transition-all duration-300 relative rounded-xl ${
      isActive
        ? 'bg-gradient-to-r from-[rgb(var(--primary))] to-[rgb(var(--accent))] text-white shadow-lg scale-[1.02]'
