import { GoogleGenAI, Type, Chat } from '@google/genai';
import type {
  RAGResult,
  CitizenAnalysisResult,
  PrecedentAnalysisResult,
  SimilarCaseAnalysisResult,
  CaseChatMessage,
  AIResearchPipelineResult,
  LegalDraftType,
  BiasAnalysisResult,
  NextStepsResponse,
  ArgumentBuilderResult,
} from '../types';

/**
 * Creates a fresh GoogleGenAI instance.
 * As per guidelines, this ensures we use the most up-to-date API Key.
 */
const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

// Model Constants - Standardizing on Gemini 3 Preview as per guidelines
const MODEL_PRO = 'gemini-3-pro-preview';
const MODEL_FLASH = 'gemini-3-flash-preview';

/**
 * Parses a JSON object from a response string.
 */
const parseResponse = <T>(text: string): T => {
  try {
    const trimmed = text.trim();
    // Sometimes the model wraps JSON in markdown blocks even with responseMimeType
    const jsonMatch = trimmed.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
    if (jsonMatch && jsonMatch[1]) {
      return JSON.parse(jsonMatch[1]);
    }
    return JSON.parse(trimmed);
  } catch (e) {
    console.error('Failed to parse response as JSON:', text);
    throw new Error('Invalid AI response format.');
  }
};

// Citizen: Analyze Dispute
export const analyzeDispute = async (
  disputeText: string
): Promise<CitizenAnalysisResult> => {
  const ai = getAi();
  const response = await ai.models.generateContent({
    model: MODEL_PRO,
    contents: `Analyze the following Indian legal dispute and provide a structured JSON response.

    Dispute Description: ${disputeText}`,
    config: {
      systemInstruction: 'You are an expert Indian Legal Consultant. Provide accurate, high-quality legal classifications and actionable remedies. Ensure recommendations follow the DPDP Act 2023 principles.',
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          case_classification: { type: Type.STRING },
          legal_domain: { type: Type.STRING },
          primary_issue: { type: Type.STRING },
          legal_summary: { type: Type.STRING },
          probable_remedy: { type: Type.ARRAY, items: { type: Type.STRING } },
          suggested_lawyer_type: { type: Type.STRING },
          recommended_lawyers: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                specialization: { type: Type.STRING },
                experience_years: { type: Type.INTEGER },
                success_rate: { type: Type.STRING },
                location: { type: Type.STRING },
                profile_id: { type: Type.STRING },
                contact_option: { type: Type.STRING },
              },
              required: ['name', 'specialization', 'experience_years', 'success_rate', 'location', 'profile_id', 'contact_option'],
            },
          },
          lawyer_request_summary: { type: Type.STRING },
          urgency: { type: Type.STRING },
          portal_recommendation: { type: Type.STRING },
        },
        required: ['case_classification', 'legal_domain', 'primary_issue', 'legal_summary', 'probable_remedy', 'suggested_lawyer_type', 'recommended_lawyers', 'lawyer_request_summary', 'urgency', 'portal_recommendation'],
      },
    },
  });

  return parseResponse(response.text);
};

// Precedent: RAG Search
export const performRAGSearch = async (
  query: string,
  documentText: string
): Promise<RAGResult> => {
  const ai = getAi();
  const prompt = `
    Context: ${documentText}
    Question: "${query}"
    Answer based ONLY on context. Provide 3 direct quotes as citations.
  `;

  const response = await ai.models.generateContent({
    model: MODEL_FLASH,
    contents: prompt,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
