const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

// Model Constants - Standardizing on Gemini 3 Preview as per guidelines
const MODEL_PRO = 'gemini-3-pro-preview';
const MODEL_FLASH = 'gemini-3-flash-preview';

// Safety settings to ensure legal reasoning is not blocked
const safetySettings = [
  { category: 'HATE_SPEECH', threshold: 'BLOCK_NONE' },
  { category: 'SEXUALLY_EXPLICIT', threshold: 'BLOCK_NONE' },
  { category: 'HARASSMENT', threshold: 'BLOCK_NONE' },
  { category: 'DANGEROUS_CONTENT', threshold: 'BLOCK_NONE' },
  { category: 'CIVIC_INTEGRITY', threshold: 'BLOCK_NONE' },
];

/**
 * Parses a JSON object from a response string.
 */
const parseResponse = <T>(text: string): T => {
  if (!text) throw new Error('AI returned an empty response.');
  try {
    const trimmed = text.trim();
    // Sometimes the model wraps JSON in markdown blocks even with responseMimeType
    const jsonMatch = trimmed.match(/\{[\s\S]*\}|\[[\s\S]*\]/);
    if (jsonMatch) {
      return JSON.parse(jsonMatch[0]);
    }
    return JSON.parse(trimmed);
  } catch (e) {
    console.error('Failed to parse response as JSON. Raw text:', text);
    throw new Error('Invalid AI response format.');
  }
};

